179→        return shiftFloorElevationData({
180→          ...floor,
181→          name: floor.name === getDefaultFloorName(previousLevelIndex)
182→            ? getDefaultFloorName(previousLevelIndex + 1)
183→            : floor.name,
184→          levelIndex: previousLevelIndex + 1,
185→        }, elevationShift);
186→      });
187→
