599→      };
600→
601→    case 'UNDO': {
602→      if (state.history.length === 0) return state;
603→      const previousProject = state.history[state.history.length - 1];
604→      return {
605→        ...state,
606→        project: previousProject,
607→        history: state.history.slice(0, -1),
608→        future: [state.project, ...state.future].slice(0, HISTORY_LIMIT),
609→        isDirty: snapshotProject(previousProject) !== state.savedSnapshot,
610→      };
611→    }
612→
613→    case 'REDO': {
614→      if (state.future.length === 0) return state;
615→      const nextProject = state.future[0];
616→      return {
617→        ...state,
618→        project: nextProject,
619→        history: [...state.history, state.project].slice(-HISTORY_LIMIT),
620→        future: state.future.slice(1),
621→        isDirty: snapshotProject(nextProject) !== state.savedSnapshot,
622→      };
623→    }
624→
625→    default:
626→      return state;
627→  }
628→}
629→
630→const initialProject = createProject();
631→
632→const initialState = {
633→  project: initialProject,
634→  isDirty: false,
635→  lastSavedAt: null,
636→  savedSnapshot: snapshotProject(initialProject),
637→  history: [],
638→  future: [],
639→};
640→
641→export function ProjectProvider({ children }) {
642→  const [state, dispatch] = useReducer(projectReducer, initialState);
643→  return (
644→    <ProjectContext.Provider value={{ state, dispatch }}>
645→      {children}
646→    </ProjectContext.Provider>
647→  );
648→}
649→
650→export function useProject() {
651→  const ctx = useContext(ProjectContext);
652→  if (!ctx) throw new Error('useProject must be used within ProjectProvider');
653→  const { state, dispatch } = ctx;
654→
655→  const duplicateFloor = (floorId) => {
656→    const floor = state.project.floors.find((entry) => entry.id === floorId) || null;
657→    return floor ? createDuplicatedFloor(floor) : null;
658→  };
659→
660→  return {
661→    project: state.project,
662→    isDirty: state.isDirty,
663→    lastSavedAt: state.lastSavedAt,
664→    canUndo: state.history.length > 0,
665→    canRedo: state.future.length > 0,
666→    dispatch,
667→    duplicateFloor,
668→    getFloor: (floorId) => state.project.floors.find(f => f.id === floorId),
669→  };
