439→      </div>
440→      <div className={styles.statusBar}>
441→        <span>X: {Math.round(cursorPos.x)} mm</span>
442→        <span>Y: {Math.round(cursorPos.y)} mm</span>
443→        <span>Zoom: {zoomPercent}%</span>
444→        <span>View: {viewMode}</span>
445→        <span>Tool: {displayedTool}</span>
446→        {liveWallBearing && <span>Bearing: {liveWallBearing}</span>}
447→        {selectionCount > 0 && <span>Selection: {selectionCount} objects</span>}
448→        {pastePreview?.active && <span>Paste: click to place</span>}
449→        {statusMessage && <span className={styles.statusMessage}>{statusMessage}</span>}
450→      </div>
451→    </div>
452→  );
453→}
