278→          </Section>
279→
280→          <Section
281→            title="Annotations"
282→            count={(floor.annotations || []).length}
283→            collapsed={collapsedSections.annotations}
284→            onToggle={() => toggleSection('annotations')}
285→          >
286→            {(floor.annotations || []).map((annotation) => (
287→              <div
288→                key={annotation.id}
289→                className={`${styles.item} ${selectedId === annotation.id ? styles.itemSelected : ''}`}
290→                onClick={() => selectObject(annotation.id, 'annotation')}
291→              >
292→                {getAnnotationDisplayLabel(annotation)}
