275→      />
276→      <InputField
277→        label="Y" type="number" suffix={u.suffix}
278→        value={u.toDisplay(wall.start.y)}
279→        onChange={(v) => updateWall({ start: { ...wall.start, y: u.fromDisplay(v) } })}
280→      />
281→      <div className={styles.subtitle}>End Point</div>
282→      <InputField
283→        label="X" type="number" suffix={u.suffix}
