286→      />
287→      <InputField
288→        label="Y" type="number" suffix={u.suffix}
289→        value={u.toDisplay(wall.end.y)}
290→        onChange={(v) => updateWall({ end: { ...wall.end, y: u.fromDisplay(v) } })}
291→      />
