 13→export default function ThreePreviewPanel({ project, activeFloorId, isMaximized = false, onToggleMaximize, className = '' }) {
 14→  const viewportRef = useRef(null);
 15→  const containerRef = useRef(null);
 16→  const resizeObserverRef = useRef(null);
 17→  const compassNeedleRef = useRef(null);
 18→  const [previewScope, setPreviewScope] = useState('all');
 19→  const [navigationMode, setNavigationMode] = useState('inspect');
 20→  const [walkUiState, setWalkUiState] = useState({
 21→    navigationMode: 'inspect',
 22→    isLocked: false,
 23→    canLock: false,
 24→  });
 25→  const { selectedId, selectedType, dispatch: editorDispatch } = useEditor();
 26→
 27→  const orderedFloors = useMemo(() => getOrderedFloors(project), [project]);
 28→
 29→  const visibleFloorIds = useMemo(() => {
 30→    if (previewScope === 'all') return undefined;
 31→    if (orderedFloors.some((f) => f.id === previewScope)) return [previewScope];
 32→    return undefined;
 33→  }, [previewScope, orderedFloors]);
 34→
 35→  const sceneDescriptor = useMemo(() => buildPreviewScene(project, {
 36→    activeFloorId,
 37→    visibleFloorIds,
 38→  }), [project, activeFloorId, visibleFloorIds]);
 39→
 40→  const activeFloor = (project?.floors || []).find((floor) => floor.id === activeFloorId) || null;
 41→  const visibleCount = sceneDescriptor.floors
 42→    .filter((floor) => floor.visible)
 43→    .reduce((count, floor) => count + floor.objects.length, 0);
 44→  const visibleFloorCount = sceneDescriptor.floors.filter((floor) => floor.visible).length;
 45→  const inspection = useMemo(
 46→    () => getPreviewInspection(project, selectedType, selectedId),
 47→    [project, selectedId, selectedType]
 48→  );
 49→  const walkFloorContext = useMemo(
 50→    () => resolveWalkFloorContext(sceneDescriptor, activeFloorId),
 51→    [sceneDescriptor, activeFloorId]
 52→  );
 53→  const visibleInspection = inspection && sceneDescriptor.visibleFloorIds.includes(inspection.floorId)
 54→    ? inspection
 55→    : null;
 56→  const handlePreviewScopeChange = useCallback((nextScope) => {
 57→    setPreviewScope(nextScope);
 58→
 59→    if (nextScope === 'all') return;
 60→    if (!orderedFloors.some((floor) => floor.id === nextScope)) return;
 61→    if (nextScope !== activeFloorId) {
 62→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: nextScope });
 63→    }
 64→  }, [activeFloorId, editorDispatch, orderedFloors]);
 65→  const handlePreviewPick = useCallback((target) => {
 66→    if (!target?.sourceId || !target?.kind) {
 67→      editorDispatch({ type: 'DESELECT' });
 68→      return;
 69→    }
 70→
 71→    if (target.floorId && target.floorId !== activeFloorId) {
 72→      editorDispatch({ type: 'SET_ACTIVE_FLOOR', floorId: target.floorId });
 73→    }
 74→
 75→    editorDispatch({ type: 'SELECT_OBJECT', id: target.sourceId, objectType: target.kind });
 76→  }, [activeFloorId, editorDispatch]);
 77→
 78→  useEffect(() => {
 79→    if (!containerRef.current) return undefined;
 80→
 81→    const viewport = createPreviewViewport(containerRef.current);
 82→    viewportRef.current = viewport;
 83→
 84→    if ('ResizeObserver' in window) {
 85→      const observer = new ResizeObserver(() => {
 86→        viewport.resize();
 87→      });
 88→      observer.observe(containerRef.current);
 89→      resizeObserverRef.current = observer;
 90→    }
 91→
 92→    viewport.resize();
 93→
 94→    return () => {
 95→      resizeObserverRef.current?.disconnect?.();
 96→      resizeObserverRef.current = null;
 97→      viewport.dispose();
 98→      viewportRef.current = null;
 99→    };
100→  }, []);
101→
102→  useEffect(() => {
103→    viewportRef.current?.setPickHandler(handlePreviewPick);
104→  }, [handlePreviewPick]);
105→
106→  useEffect(() => {
107→    viewportRef.current?.setPickContext({ activeFloorId });
108→  }, [activeFloorId]);
109→
110→  useEffect(() => {
111→    viewportRef.current?.setWalkUiHandler(setWalkUiState);
112→    viewportRef.current?.setWalkExitHandler(() => {
113→      setNavigationMode('inspect');
114→    });
115→  }, []);
116→
117→  useEffect(() => {
118→    viewportRef.current?.setCompassHeadingHandler((headingDeg) => {
119→      if (!compassNeedleRef.current) return;
120→      compassNeedleRef.current.style.setProperty('--compass-heading', `${headingDeg}deg`);
121→    });
122→
123→    return () => {
124→      viewportRef.current?.setCompassHeadingHandler(null);
125→    };
126→  }, []);
127→
128→  useEffect(() => {
129→    const viewport = viewportRef.current;
130→    if (!viewport) return;
131→
