  1→import { buildElevationAnnotationScene } from '@/elevations/annotations';
  2→import { buildProjectElevationScene } from '@/elevations/scene';
  3→import { getDefaultActiveFloorId, resolveProjectFloor } from '@/domain/floorModels';
  4→import { getBeamRenderData } from '@/geometry/beamGeometry';
  5→import { columnOutline } from '@/geometry/columnGeometry';
  6→import { landingOutline } from '@/geometry/landingGeometry';
  7→import { getSectionCutRenderData } from '@/geometry/sectionCutGeometry';
  8→import { getSlabRenderData } from '@/geometry/slabGeometry';
  9→import { getStairRenderData } from '@/geometry/stairGeometry';
 10→import { fixtureOutline } from '@/geometry/fixtureGeometry';
 11→import { doorOutlineOnWall, windowOutlineOnWall } from '@/geometry/wallGeometry';
 12→import { getWallRenderData } from '@/geometry/wallColumnGeometry';
 13→import { buildProjectSectionScene } from '@/sections/scene';
 14→
 15→const PLAN_PADDING = 1500;
 16→const VERTICAL_PADDING = 700;
 17→const TOP_PADDING = 1100;
 18→
 19→function boundsFromPoints(points = [], fallback = { minX: -1000, maxX: 1000, minY: -1000, maxY: 1000 }) {
 20→  if (!points.length) return fallback;
 21→  return {
 22→    minX: Math.min(...points.map((point) => point.x)),
 23→    maxX: Math.max(...points.map((point) => point.x)),
 24→    minY: Math.min(...points.map((point) => point.y)),
 25→    maxY: Math.max(...points.map((point) => point.y)),
 26→  };
 27→}
 28→
 29→function expandBounds(bounds, paddingX, paddingY = paddingX) {
 30→  return {
 31→    minX: bounds.minX - paddingX,
 32→    maxX: bounds.maxX + paddingX,
 33→    minY: bounds.minY - paddingY,
 34→    maxY: bounds.maxY + paddingY,
 35→  };
 36→}
 37→
 38→function collectPlanPoints(floor) {
 39→  const points = [];
 40→
 41→  for (const wall of floor.walls || []) {
 42→    points.push(...(getWallRenderData(wall, floor.columns || []).outline || []));
 43→  }
 44→  for (const room of floor.rooms || []) {
 45→    points.push(...(room.points || []));
 46→  }
 47→  for (const beam of floor.beams || []) {
 48→    const renderData = getBeamRenderData(beam, floor.columns || []);
 49→    if (renderData?.outline) points.push(...renderData.outline);
 50→  }
 51→  for (const stair of floor.stairs || []) {
 52→    const renderData = getStairRenderData(stair);
 53→    if (renderData?.outline) points.push(...renderData.outline);
 54→  }
 55→  for (const landing of floor.landings || []) {
 56→    points.push(...landingOutline(landing));
 57→  }
 58→  for (const column of floor.columns || []) {
 59→    points.push(...columnOutline(column));
 60→  }
 61→  for (const slab of (floor.slabs || [])) {
 62→    const rd = getSlabRenderData(slab);
 63→    if (rd?.boundaryPoints) points.push(...rd.boundaryPoints);
 64→  }
 65→  for (const sc of (floor.sectionCuts || [])) {
 66→    points.push(sc.startPoint, sc.endPoint);
 67→    const renderData = getSectionCutRenderData(sc);
 68→    if (renderData?.arrow) {
 69→      points.push(renderData.arrow.shaftStart, renderData.arrow.shaftEnd, renderData.arrow.headA, renderData.arrow.headB);
 70→    }
 71→  }
 72→
 73→  for (const door of floor.doors || []) {
 74→    const wall = (floor.walls || []).find((entry) => entry.id === door.wallId);
 75→    if (!wall) continue;
 76→    const outline = doorOutlineOnWall(wall, door);
 77→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 78→  }
 79→
 80→  for (const windowItem of floor.windows || []) {
 81→    const wall = (floor.walls || []).find((entry) => entry.id === windowItem.wallId);
 82→    if (!wall) continue;
 83→    const outline = windowOutlineOnWall(wall, windowItem);
 84→    points.push(outline.p1, outline.p2, outline.p3, outline.p4);
 85→  }
 86→
 87→  for (const fixture of floor.fixtures || []) {
 88→    points.push(...fixtureOutline(fixture));
 89→  }
 90→
 91→  return points;
 92→}
 93→
 94→function buildPlanSource(floor) {
 95→  if (!floor) {
 96→    return {
 97→      kind: 'empty',
 98→      title: 'Plan',
 99→      message: 'Missing floor.',
100→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
101→    };
102→  }
103→
104→  const geometryBounds = expandBounds(boundsFromPoints(collectPlanPoints(floor)), PLAN_PADDING);
105→
106→  return {
107→    kind: 'plan',
108→    title: `${floor.name} Plan`,
109→    floor,
110→    bounds: geometryBounds,
111→  };
112→}
113→
114→function sceneBoundsToRenderBounds(scene) {
115→  return {
116→    minX: scene.bounds.minX - VERTICAL_PADDING,
117→    maxX: scene.bounds.maxX + VERTICAL_PADDING,
118→    minY: -scene.bounds.maxZ - TOP_PADDING,
119→    maxY: -scene.bounds.minZ + VERTICAL_PADDING,
120→  };
121→}
122→
123→function buildSectionSource(project, floor, sourceRefId) {
124→  const cuts = floor?.sectionCuts || [];
125→  const sectionCut = sourceRefId
126→    ? cuts.find(s => s.id === sourceRefId)
127→    : cuts[0] || null;
128→
129→  if (!sectionCut) {
130→    return {
131→      kind: 'empty',
132→      title: 'Section',
133→      message: 'No section cut on this floor.',
134→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
135→    };
136→  }
137→
138→  const scene = buildProjectSectionScene(project, floor.id, sectionCut.id);
139→  return {
140→    kind: 'section',
141→    title: sectionCut.label || 'Section',
142→    floor,
143→    scene,
144→    bounds: sceneBoundsToRenderBounds(scene),
145→  };
146→}
147→
148→function buildElevationSource(project, floor, sourceView) {
149→  if (!floor) {
150→    return {
151→      kind: 'empty',
152→      title: 'Elevation',
153→      message: 'Missing floor.',
154→      bounds: { minX: 0, maxX: 2000, minY: -3000, maxY: 1000 },
155→    };
156→  }
157→
158→  const scene = buildProjectElevationScene(project, floor.id, sourceView);
159→  const annotationScene = buildElevationAnnotationScene(floor, scene);
160→
161→  return {
162→    kind: 'elevation',
163→    title: scene.title,
164→    floor,
165→    viewMode: sourceView,
166→    scene,
167→    annotationScene,
168→    bounds: sceneBoundsToRenderBounds(scene),
169→  };
170→}
171→
172→function build3DPreviewSource(project, floor) {
173→  if (!floor) {
174→    return {
175→      kind: 'empty',
176→      title: 'Axonometric View',
177→      message: 'Missing floor.',
178→      bounds: { minX: 0, maxX: 2000, minY: 0, maxY: 1500 },
179→    };
180→  }
181→
182→  // Use 16:10 aspect ratio matching render resolution (1600x1000).
183→  // At scale 100, this fills a 160x100mm viewport on paper.
184→  const imageWidth = 16000;
185→  const imageHeight = 10000;
186→
187→  return {
188→    kind: '3d_preview',
189→    title: 'Axonometric View',
190→    project,
191→    activeFloorId: floor.id,
192→    bounds: {
193→      minX: 0,
194→      maxX: imageWidth,
195→      minY: 0,
196→      maxY: imageHeight,
197→    },
198→  };
199→}
200→
201→export function resolveSheetViewportSource(project, viewport) {
202→  const defaultFloorId = getDefaultActiveFloorId(project, viewport.sourceFloorId);
203→  const floor = resolveProjectFloor(project, defaultFloorId);
204→
205→  switch (viewport.sourceView) {
206→    case '3d_preview':
207→      return build3DPreviewSource(project, floor);
208→    case 'section':
209→      return buildSectionSource(project, floor, viewport.sourceRefId);
210→    case 'elevation_front':
211→    case 'elevation_rear':
212→    case 'elevation_left':
213→    case 'elevation_right':
214→      return buildElevationSource(project, floor, viewport.sourceView);
215→    case 'plan':
216→    default:
217→      return buildPlanSource(floor);
218→  }
219→}
220→
221→export function getViewportSourceLabel(sourceView) {
222→  switch (sourceView) {
223→    case '3d_preview':
224→      return 'Axonometric View';
225→    case 'section':
226→      return 'Section';
227→    case 'elevation_front':
228→      return 'Front Elevation';
229→    case 'elevation_rear':
230→      return 'Rear Elevation';
231→    case 'elevation_left':
232→      return 'Left Elevation';
233→    case 'elevation_right':
234→      return 'Right Elevation';
235→    case 'plan':
236→    default:
237→      return 'Plan';
238→  }
239→}
