      if (win.sillHeight === undefined) win.sillHeight = WINDOW_SILL_HEIGHT;
    }
    if (!floor.columns) floor.columns = [];
    if (!floor.fixtures) floor.fixtures = [];
    if (!floor.beams) floor.beams = [];
