      if (!sc.endPoint) sc.endPoint = { x: 1000, y: 0 };
      if (sc.depth === undefined) sc.depth = 2000;
      if (sc.label === undefined) sc.label = 'Section A-A';
      if (sc.direction === undefined) sc.direction = 1;
