    sheet.revisions = sheet.revisions.map((revision) => ({
      ...createSheetRevision(),
      ...revision,
      id: revision?.id || `revision_${sheet.id}_${Math.random().toString(36).slice(2, 8)}`,
    }));
    if (!Array.isArray(sheet.viewports)) sheet.viewports = [];

