import { useEffect, useRef, useState } from 'react';
import { useProject } from '@/app/ProjectProvider';
import { useEditor } from '@/app/EditorProvider';
import { formatMeasurement, getAnnotationDisplayLabel } from '@/annotations/format';
import { MIN_WALL_LENGTH } from '@/domain/defaults';
import { getBeamDisplayLabel } from '@/domain/beamLabels';
import { getDefaultActiveFloorId, getFloorElevation, getFloorLevelIndex, getFloorToFloorHeight, getOrderedFloors } from '@/domain/floorModels';
import { getSlabDisplayLabel } from '@/domain/slabLabels';
import { getStairDisplayLabel } from '@/domain/stairLabels';
import { createSheetRevision, createSheetViewport } from '@/domain/sheetModels';
import { exportActiveSheetAsPdf, exportActiveSheetAsPng } from '@/export/sheetExport';
import { resizeWallFromStart, wallLength } from '@/geometry/wallGeometry';
import { normalize, subtract, add, scale } from '@/geometry/point';
import { getColumnAutoLabel, getColumnListLabel } from '@/domain/columnLabels';
import { duplicateColumn } from '@/domain/columnModels';
import { beamLength } from '@/geometry/beamGeometry';
import { slabArea } from '@/geometry/slabGeometry';
import { stairRun, stairTotalRise } from '@/geometry/stairGeometry';
import { computeLandingElevation } from '@/geometry/landingGeometry';
import { getLandingDisplayLabel } from '@/domain/landingLabels';
import { sectionCutLength } from '@/geometry/sectionCutGeometry';
import { railingLength } from '@/geometry/railingGeometry';
import { RAILING_TYPES } from '@/editor/tools';
import { getManualAnnotationFigure } from '@/annotations/scene';
import {
  buildSheetScene,
  fitViewportToSheet,
  getDefaultViewportRect,
  materializeSheetViewportFrames,
} from '@/sheets/layout';
import { listPaperPresets } from '@/sheets/paper';
import { getViewportSourceLabel, resolveSheetViewportSource } from '@/sheets/sources';
import { FIXTURE_TYPES, TOOLS } from '@/editor/tools';
import { createWall } from '@/domain/models';
import { formatSurveyorBearing, pointsToSurveyorBearing, surveyorBearingToSvgAngle, endpointFromBearing } from '@/geometry/bearing';
import { getOrderedPhases, PHASE_COLORS } from '@/domain/phaseModels';
import InputField from './InputField';
import styles from './PropertiesPanel.module.css';

function useUnits() {
  const [unit, setUnit] = useState('mm');
  const isMm = unit === 'mm';
  return {
    unit,
    setUnit,
    suffix: isMm ? 'mm' : 'm',
    toDisplay: (mm) => isMm ? +mm.toFixed(1) : +(mm / 1000).toFixed(4),
    fromDisplay: (v) => isMm ? v : v * 1000,
    step: (mmStep) => isMm ? mmStep : mmStep / 1000,
  };
}

function WallDrawingInput({ start, preview, dispatch, editorDispatch, activeFloorId, u, selectNewWall }) {
  const [nsDir, setNsDir] = useState('N');
  const [ewDir, setEwDir] = useState('E');
  const [degrees, setDegrees] = useState('');
  const [minutes, setMinutes] = useState('');
  const [lengthVal, setLengthVal] = useState('');
  const lengthRef = useRef(null);
  const livePreviewLength = preview ? formatMeasurement(wallLength({ start, end: preview })) : '';
  const livePreviewBearing = preview ? formatSurveyorBearing(pointsToSurveyorBearing(start, preview)) : '';

  const handleConfirm = () => {
    const deg = parseInt(degrees, 10) || 0;
    const min = parseInt(minutes, 10) || 0;
    const len = u.fromDisplay(parseFloat(lengthVal) || 0);

    if (len < MIN_WALL_LENGTH) return;
    if (deg < 0 || deg > 90 || min < 0 || min > 59) return;

    const angle = surveyorBearingToSvgAngle(nsDir, deg, min, ewDir);
    const endPt = endpointFromBearing(start, len, angle);
    const wall = createWall(start, endPt);

    dispatch({ type: 'WALL_ADD', floorId: activeFloorId, wall });
    if (selectNewWall) {
      editorDispatch({ type: 'SELECT_OBJECT', id: wall.id, objectType: 'wall' });
    } else {
      editorDispatch({
        type: 'UPDATE_TOOL_STATE',
        payload: { start: endPt, startAttachment: null, preview: null },
      });
    }

    setDegrees('');
    setMinutes('');
    setLengthVal('');
    setTimeout(() => lengthRef.current?.focus(), 0);
  };

  const handleKeyDown = (e) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleConfirm();
    }
  };

  return (
    <div>
      {!selectNewWall && (
        <>
          <div className={styles.title}>Drawing Wall</div>
          <div style={{ fontSize: 12, color: 'var(--color-text-secondary)', marginBottom: 'var(--space-sm)' }}>
            Start: ({u.toDisplay(start.x)}, {u.toDisplay(start.y)}) {u.suffix}
          </div>
        </>
      )}
      {preview && (
        <div className={styles.drawingMeta}>
          Cursor: {livePreviewLength} · {livePreviewBearing}
        </div>
      )}
      <div className={styles.drawingHint}>
        Hold Shift while drawing to snap the wall bearing to 45° increments.
      </div>

      <div className={styles.subtitle}>Bearing</div>
      <div className={styles.bearingRow}>
        <select className={styles.bearingSelect} value={nsDir} onChange={(e) => setNsDir(e.target.value)}>
          <option value="N">N</option>
          <option value="S">S</option>
        </select>
        <input
          className={styles.bearingInput}
          type="number"
          min={0}
          max={90}
          placeholder="0"
          value={degrees}
          onChange={(e) => setDegrees(e.target.value)}
          onKeyDown={handleKeyDown}
        />
        <span className={styles.bearingSymbol}>°</span>
        <input
          className={styles.bearingInput}
          type="number"
          min={0}
          max={59}
          placeholder="0"
          value={minutes}
          onChange={(e) => setMinutes(e.target.value)}
          onKeyDown={handleKeyDown}
        />
        <span className={styles.bearingSymbol}>′</span>
        <select className={styles.bearingSelect} value={ewDir} onChange={(e) => setEwDir(e.target.value)}>
          <option value="E">E</option>
          <option value="W">W</option>
        </select>
      </div>

      <div className={styles.subtitle}>Length</div>
      <input
        ref={lengthRef}
        className={styles.bearingInput}
        style={{ width: '100%', textAlign: 'left', padding: '0 8px', marginBottom: 'var(--space-sm)' }}
        type="number"
        min={0}
        step={u.step(100)}
        placeholder={`0 ${u.suffix}`}
        value={lengthVal}
        onChange={(e) => setLengthVal(e.target.value)}
        onKeyDown={handleKeyDown}
      />

      <button className={styles.confirmBtn} onClick={handleConfirm}>
        Create Wall (Enter)
      </button>
    </div>
  );
}

function SheetExportMenu({ sheet, editorDispatch }) {
  const [open, setOpen] = useState(false);
  const rootRef = useRef(null);
  const pngOptions = [
    { label: 'PNG 150 DPI', dpi: 150 },
    { label: 'PNG 300 DPI', dpi: 300 },
    { label: 'PNG 600 DPI', dpi: 600 },
  ];

  useEffect(() => {
    if (!open) return undefined;

    const handleMouseDown = (event) => {
      if (rootRef.current && !rootRef.current.contains(event.target)) {
        setOpen(false);
      }
    };

    document.addEventListener('mousedown', handleMouseDown);
    return () => document.removeEventListener('mousedown', handleMouseDown);
  }, [open]);

  const handleExport = async (kind, options = {}) => {
    if (!sheet) return;
    try {
      if (kind === 'pdf') {
        await exportActiveSheetAsPdf(
          sheet.title || sheet.drawingName || 'sheet',
          sheet.paperSize
        );
        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: 'Exported sheet as PDF.' });
      } else {
        await exportActiveSheetAsPng(
          sheet.title || sheet.drawingName || 'sheet',
          options
        );
        const dpiLabel = options.dpi ? ` (${options.dpi} DPI)` : '';
        editorDispatch({ type: 'SET_STATUS_MESSAGE', message: `Exported sheet as PNG${dpiLabel}.` });
      }
    } catch (error) {
      editorDispatch({
        type: 'SET_STATUS_MESSAGE',
        message: error.message || `${kind.toUpperCase()} export failed.`,
      });
    } finally {
      setOpen(false);
    }
  };

  return (
    <div className={styles.exportMenu} ref={rootRef}>
      <button
        className={styles.exportMenuTrigger}
        type="button"
        onClick={() => setOpen((value) => !value)}
      >
        Export sheet
        <span className={styles.exportMenuChevron}>{open ? '▴' : '▾'}</span>
      </button>
      {open && (
        <div className={styles.exportMenuList}>
          <button
            className={styles.exportMenuItem}
            type="button"
            onClick={() => handleExport('pdf')}
          >
            PDF
          </button>
          {pngOptions.map((option) => (
            <button
              key={option.dpi}
              className={styles.exportMenuItem}
              type="button"
              onClick={() => handleExport('png', { dpi: option.dpi })}
            >
              {option.label}
            </button>
          ))}
        </div>
      )}
    </div>
  );
}

function PhaseSelector({ phaseId, phases, onChange }) {
  return (
    <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
      <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Phase</label>
      <select
        value={phaseId || ''}
        onChange={(e) => onChange(e.target.value || null)}
        style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)',
                 borderRadius: 'var(--radius-sm)', fontSize: '12px', background: 'var(--color-surface-elevated)' }}
      >
        <option value="">Unassigned</option>
        {phases.map(p => <option key={p.id} value={p.id}>{p.name}</option>)}
      </select>
    </div>
  );
}

function PhaseProperties({ phase, project, dispatch }) {
  const updatePhase = (updates) => {
    dispatch({ type: 'PHASE_UPDATE', phase: { id: phase.id, ...updates } });
  };

  const countObjectsInPhase = () => {
    let count = 0;
    const keys = ['walls', 'doors', 'windows', 'columns', 'beams', 'slabs',
      'stairs', 'landings', 'fixtures', 'rooms', 'railings'];
    for (const floor of project.floors) {
      for (const key of keys) {
        for (const obj of floor[key] || []) {
          if (obj.phaseId === phase.id) count++;
        }
      }
    }
    return count;
  };

  return (
    <div>
      <div className={styles.title}>Phase</div>
      <InputField
        label="Name"
        value={phase.name}
        onChange={(value) => updatePhase({ name: value })}
      />
      <div className={styles.colorField}>
        <label className={styles.colorLabel}>Color</label>
        <div className={styles.colorControls}>
          <input
            className={styles.colorPicker}
            type="color"
            value={phase.color}
            onChange={(e) => updatePhase({ color: e.target.value })}
            aria-label="Phase color"
          />
          <input
            className={styles.colorHexInput}
            type="text"
            value={phase.color}
            onChange={(e) => {
              const hex = e.target.value;
              if (/^#[0-9a-fA-F]{6}$/.test(hex)) updatePhase({ color: hex });
            }}
            onBlur={(e) => {
              let hex = e.target.value.trim();
              if (!hex.startsWith('#')) hex = '#' + hex;
              if (/^#[0-9a-fA-F]{6}$/.test(hex)) updatePhase({ color: hex });
            }}
          />
        </div>
      </div>
      <InputField label="Order" value={phase.order} readOnly />
      <InputField label="Objects" value={countObjectsInPhase()} readOnly />
    </div>
  );
}

function WallProperties({ wall, dispatch, editorDispatch, floorId, u, phases }) {
  const len = wallLength(wall);

  const updateWall = (updates) => {
    dispatch({ type: 'WALL_UPDATE', floorId, wall: { id: wall.id, ...updates } });
  };

  const updateWallLength = (value) => {
    const resizedWall = resizeWallFromStart(wall, u.fromDisplay(value), MIN_WALL_LENGTH);
    updateWall({ end: resizedWall.end });
  };

  return (
    <div>
      <div className={styles.title}>Wall</div>
      <PhaseSelector phaseId={wall.phaseId} phases={phases} onChange={(v) => updateWall({ phaseId: v })} />
      <div className={styles.subtitle}>Start Point</div>
      <InputField
        label="X" type="number" suffix={u.suffix}
        value={u.toDisplay(wall.start.x)}
        onChange={(v) => updateWall({ start: { ...wall.start, x: u.fromDisplay(v) } })}
      />
      <InputField
        label="Y" type="number" suffix={u.suffix}
        value={u.toDisplay(wall.start.y)}
        onChange={(v) => updateWall({ start: { ...wall.start, y: u.fromDisplay(v) } })}
      />
      <div className={styles.subtitle}>End Point</div>
      <InputField
        label="X" type="number" suffix={u.suffix}
        value={u.toDisplay(wall.end.x)}
        onChange={(v) => updateWall({ end: { ...wall.end, x: u.fromDisplay(v) } })}
      />
      <InputField
        label="Y" type="number" suffix={u.suffix}
        value={u.toDisplay(wall.end.y)}
        onChange={(v) => updateWall({ end: { ...wall.end, y: u.fromDisplay(v) } })}
      />
      <div className={styles.subtitle}>Properties</div>
      <InputField
        label="Thickness" type="number" suffix={u.suffix} step={u.step(10)}
        value={u.toDisplay(wall.thickness)}
        onChange={(v) => updateWall({ thickness: Math.max(50, u.fromDisplay(v)) })}
      />
      <InputField
        label="Height" type="number" suffix={u.suffix} step={u.step(100)}
        value={u.toDisplay(wall.height)}
        onChange={(v) => updateWall({ height: Math.max(100, u.fromDisplay(v)) })}
      />
      <InputField
        label="Length" type="number" suffix={u.suffix} step={u.step(100)}
        value={u.toDisplay(len)}
        onChange={updateWallLength}
      />
      <div className={styles.subtitle}>Continue from End</div>
      <WallDrawingInput
        start={wall.end}
        dispatch={dispatch}
        editorDispatch={editorDispatch}
        activeFloorId={floorId}
        u={u}
        selectNewWall
      />
    </div>
  );
}

function DoorProperties({ door, wall, dispatch, floorId, editorDispatch, u, phases }) {
  const updateDoor = (updates) => {
    dispatch({ type: 'DOOR_UPDATE', floorId, door: { id: door.id, ...updates } });
  };

  const doorType = door.type || 'swing';

  return (
    <div>
      <div className={styles.title}>Door</div>
      <PhaseSelector phaseId={door.phaseId} phases={phases} onChange={(v) => updateDoor({ phaseId: v })} />
      <div style={{ display: 'flex', alignItems: 'center', gap: '8px', marginBottom: '8px' }}>
        <label style={{ flex: '0 0 80px', fontSize: '12px', color: 'var(--color-text-secondary)' }}>Type</label>
        <select value={doorType} onChange={(e) => updateDoor({ type: e.target.value })}
          style={{ flex: 1, height: '28px', padding: '0 4px', border: '1px solid var(--color-border)',
                   borderRadius: 'var(--radius-sm)', fontSize: '12px', background: 'var(--color-surface-elevated)' }}>
          <option value="swing">Swing</option>
          <option value="double">Double</option>
          <option value="sliding">Sliding</option>
        </select>
      </div>
      <InputField
        label="Width" type="number" suffix={u.suffix} step={u.step(50)}
        value={u.toDisplay(door.width)}
        onChange={(v) => updateDoor({ width: Math.max(400, u.fromDisplay(v)) })}
      />
      <InputField
        label="Height" type="number" suffix={u.suffix} step={u.step(50)}
        value={u.toDisplay(door.height)}
        onChange={(v) => updateDoor({ height: Math.max(300, u.fromDisplay(v)) })}
      />
      <InputField
        label="Sill" type="number" suffix={u.suffix} step={u.step(50)}
        value={u.toDisplay(door.sillHeight)}
        onChange={(v) => updateDoor({ sillHeight: u.fromDisplay(v) })}
      />
      <InputField
        label="Offset" type="number" suffix={u.suffix}
