  1→import { createContext, useContext, useEffect, useReducer } from 'react';
  2→import { TOOLS } from '@/editor/tools';
  3→import { DEFAULT_ZOOM } from '@/domain/defaults';
  4→
  5→const EditorContext = createContext(null);
  6→
  7→function normalizeViewMode(viewMode) {
  8→  if (viewMode === 'elevation_side') return 'elevation_left';
  9→  return viewMode;
 10→}
 11→
 12→function getInitialModelViewport() {
 13→  return { panX: 400, panY: 300, zoom: DEFAULT_ZOOM };
 14→}
 15→
 16→function getInitialSheetViewport() {
 17→  return { panX: 120, panY: 80, zoom: 2 };
 18→}
 19→
 20→function clearSelectionState(state) {
 21→  return {
 22→    ...state,
 23→    selectedId: null,
 24→    selectedType: null,
 25→    regionSelection: null,
 26→    pastePreview: { active: false, point: null },
 27→  };
 28→}
 29→
 30→function editorReducer(state, action) {
 31→  switch (action.type) {
 32→    case 'SET_TOOL':
 33→      return {
 34→        ...clearSelectionState(state),
 35→        activeTool: action.tool,
 36→        toolState: {},
 37→        statusMessage: null,
 38→      };
 39→
 40→    case 'SET_VIEW_MODE':
 41→      return {
 42→        ...clearSelectionState(state),
 43→        workspaceMode: 'model',
 44→        viewMode: normalizeViewMode(action.viewMode),
 45→        activeSectionCutId: action.sectionCutId ?? state.activeSectionCutId,
 46→        viewport: { ...state.modelViewport },
 47→        toolState: {},
 48→        statusMessage: null,
 49→      };
 50→
 51→    case 'SET_WORKSPACE_MODE':
 52→      return {
 53→        ...clearSelectionState(state),
 54→        workspaceMode: action.workspaceMode,
 55→        viewport: action.workspaceMode === 'sheet'
 56→          ? { ...state.sheetViewport }
 57→          : { ...state.modelViewport },
 58→        toolState: {},
 59→        statusMessage: null,
 60→      };
 61→
 62→    case 'SET_ACTIVE_SHEET':
 63→      return {
 64→        ...clearSelectionState(state),
 65→        activeSheetId: action.sheetId,
 66→        statusMessage: null,
 67→      };
 68→
 69→    case 'SELECT_OBJECT':
 70→      return {
 71→        ...clearSelectionState(state),
 72→        selectedId: action.id,
 73→        selectedType: action.objectType,
 74→      };
 75→
 76→    case 'DESELECT':
 77→      return clearSelectionState(state);
 78→
 79→    case 'SET_REGION_SELECTION':
 80→      return {
 81→        ...clearSelectionState(state),
 82→        regionSelection: action.selection && action.bounds
 83→          ? {
 84→              bounds: action.bounds,
 85→              selection: action.selection,
 86→              objectCount: Object.values(action.selection).reduce((count, ids) => count + (ids?.length || 0), 0),
 87→            }
 88→          : null,
 89→      };
 90→
 91→    case 'UPDATE_TOOL_STATE':
 92→      return {
 93→        ...state,
 94→        toolState: { ...state.toolState, ...action.payload },
 95→      };
 96→
 97→    case 'SET_VIEWPORT':
 98→      return {
 99→        ...state,
100→        modelViewport: state.workspaceMode === 'model' ? { ...action.viewport } : state.modelViewport,
101→        sheetViewport: state.workspaceMode === 'sheet' ? { ...action.viewport } : state.sheetViewport,
102→        viewport: { ...action.viewport },
103→      };
104→
105→    case 'PAN':
106→      return {
107→        ...state,
108→        modelViewport: state.workspaceMode === 'model'
109→          ? {
110→              ...state.modelViewport,
111→              panX: state.modelViewport.panX + action.dx,
112→              panY: state.modelViewport.panY + action.dy,
113→            }
114→          : state.modelViewport,
115→        sheetViewport: state.workspaceMode === 'sheet'
116→          ? {
117→              ...state.sheetViewport,
118→              panX: state.sheetViewport.panX + action.dx,
119→              panY: state.sheetViewport.panY + action.dy,
120→            }
121→          : state.sheetViewport,
122→        viewport: {
123→          ...state.viewport,
124→          panX: state.viewport.panX + action.dx,
125→          panY: state.viewport.panY + action.dy,
126→        },
127→      };
128→
129→    case 'ZOOM': {
130→      const { zoom, panX, panY } = action;
131→      return {
132→        ...state,
133→        modelViewport: state.workspaceMode === 'model' ? { zoom, panX, panY } : state.modelViewport,
134→        sheetViewport: state.workspaceMode === 'sheet' ? { zoom, panX, panY } : state.sheetViewport,
135→        viewport: { zoom, panX, panY },
136→      };
137→    }
138→
139→    case 'TOGGLE_GRID':
140→      return { ...state, showGrid: !state.showGrid };
141→
142→    case 'TOGGLE_SNAP':
143→      return { ...state, snapEnabled: !state.snapEnabled };
144→
145→    case 'SET_ACTIVE_FLOOR':
146→      return {
147→        ...clearSelectionState(state),
148→        activeFloorId: action.floorId,
149→        toolState: {},
150→        statusMessage: null,
151→      };
152→
153→    case 'SET_STATUS_MESSAGE':
154→      return { ...state, statusMessage: action.message };
155→
156→    case 'CLEAR_STATUS_MESSAGE':
157→      if (!state.statusMessage) return state;
158→      return { ...state, statusMessage: null };
159→
160→    case 'START_PASTE_PREVIEW':
161→      return {
162→        ...state,
163→        selectedId: null,
164→        selectedType: null,
165→        regionSelection: null,
166→        pastePreview: {
167→          active: true,
168→          point: action.point ?? null,
169→        },
170→      };
171→
172→    case 'UPDATE_PASTE_PREVIEW':
173→      if (!state.pastePreview?.active) return state;
174→      return {
175→        ...state,
176→        pastePreview: {
177→          active: true,
178→          point: action.point,
179→        },
180→      };
181→
182→    case 'CANCEL_PASTE_PREVIEW':
183→      if (!state.pastePreview?.active) return state;
184→      return {
185→        ...state,
186→        pastePreview: {
187→          active: false,
188→          point: null,
189→        },
190→      };
191→
192→    case 'TOGGLE_MAXIMIZE_PANEL':
193→      return {
194→        ...state,
195→        maximizedPanel: state.maximizedPanel === action.panel ? null : action.panel,
196→      };
197→
198→    case 'SET_ACTIVE_PHASE':
199→      return { ...state, activePhaseId: action.phaseId };
200→
201→    case 'SET_PHASE_VIEW_MODE':
202→      return { ...state, phaseViewMode: action.mode };
203→
204→    default:
205→      return state;
206→  }
207→}
208→
209→export function createInitialEditorState(activeFloorId = null) {
210→  const modelViewport = getInitialModelViewport();
211→  const sheetViewport = getInitialSheetViewport();
212→  return {
213→    activeTool: TOOLS.SELECT,
214→    selectedId: null,
215→    selectedType: null,
216→    toolState: {},
217→    workspaceMode: 'model',
218→    viewport: { ...modelViewport },
219→    modelViewport,
220→    sheetViewport,
221→    showGrid: true,
222→    snapEnabled: true,
223→    viewMode: 'plan',
224→    activeFloorId,
225→    activeSheetId: null,
226→    activeSectionCutId: null,
227→    statusMessage: null,
228→    regionSelection: null,
229→    pastePreview: { active: false, point: null },
230→    maximizedPanel: null,
231→    activePhaseId: null,
232→    phaseViewMode: 'all',
233→  };
234→}
235→
236→export function EditorProvider({ children, initialActiveFloorId = null, availableFloorIds = [], availablePhaseIds = [] }) {
237→  const [state, dispatch] = useReducer(
238→    editorReducer,
239→    initialActiveFloorId,
240→    createInitialEditorState
241→  );
242→
243→  useEffect(() => {
244→    if (!availableFloorIds.length) {
245→      if (state.activeFloorId !== null) {
246→        dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: null });
247→      }
248→      return;
249→    }
250→
251→    if (!state.activeFloorId || !availableFloorIds.includes(state.activeFloorId)) {
252→      dispatch({ type: 'SET_ACTIVE_FLOOR', floorId: availableFloorIds[0] });
253→    }
254→  }, [availableFloorIds, state.activeFloorId]);
255→
256→  useEffect(() => {
257→    if (state.activePhaseId && !availablePhaseIds.includes(state.activePhaseId)) {
258→      dispatch({ type: 'SET_ACTIVE_PHASE', phaseId: null });
259→      dispatch({ type: 'SET_PHASE_VIEW_MODE', mode: 'all' });
260→    }
261→  }, [availablePhaseIds, state.activePhaseId]);
262→
263→  return (
264→    <EditorContext.Provider value={{ state, dispatch }}>
265→      {children}
266→    </EditorContext.Provider>
267→  );
268→}
269→
270→export function useEditor() {
271→  const ctx = useContext(EditorContext);
272→  if (!ctx) throw new Error('useEditor must be used within EditorProvider');
273→  return { ...ctx.state, dispatch: ctx.dispatch };
274→}
