201→        />
202→      </Section>
203→
204→      <Section
205→        title="Floors"
206→        count={orderedFloors.length}
207→        collapsed={collapsedSections.floors}
208→        onToggle={() => toggleSection('floors')}
209→        action={
210→          <button type="button" className={styles.sectionAddBtn} onClick={addFloor} title="Add Floor">+</button>
211→        }
212→      >
213→        {orderedFloors.map((entry) => (
214→          <div
215→            key={entry.id}
216→            className={`${styles.floorCard} ${entry.id === activeFloorId ? styles.floorCardActive : ''}`}
217→          >
218→            <button
219→              type="button"
220→              className={styles.floorButton}
221→              onClick={() => selectFloor(entry.id)}
222→            >
223→              <span className={styles.floorName}>{entry.name}</span>
224→              <span className={styles.floorMeta}>
225→                L{getFloorLevelIndex(entry)} · {Math.round(getFloorElevation(entry))} mm
226→              </span>
227→            </button>
228→            <div className={styles.floorActions}>
229→              <button
