 50→function screenToModel(screenX, screenY, viewport, svgRect) {
 51→  const x = (screenX - svgRect.left - viewport.panX) / viewport.zoom;
 52→  const y = (screenY - svgRect.top - viewport.panY) / viewport.zoom;
 53→  return { x, y };
 54→}
